INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Web Clipper$q$, $q$A browser extension that saves full web pages, simplified articles, screenshots, or PDFs directly into an Evernote notebook, preserving formatting and the source link.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Rich note editor$q$, $q$A rich-text editor with tables, checklists, attachments, and slash commands for quickly inserting content blocks into any note.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$AI Assistant$q$, $q$An AI Assistant, built in collaboration with OpenAI, that can summarize notes, extract action items, and rewrite or rephrase text from within a note.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Semantic Search$q$, $q$A natural-language search mode that surfaces relevant notes and details by meaning rather than requiring exact keyword matches.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$AI Meeting Notes$q$, $q$A feature that records, transcribes, and summarizes in-person and online meetings with support for multiple speakers, directly inside Evernote.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Document and handwriting search$q$, $q$Built-in OCR indexes text inside scanned documents, photos, and handwritten notes so it can be found through a normal search query.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Document scanning$q$, $q$Mobile document scanning that turns a phone camera into a scanner for receipts, whiteboards, and paper documents, saved directly as searchable notes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Notebooks, tags, and stacks$q$, $q$A flexible organization system using notebooks, notebook stacks, and tags to structure a large, growing collection of notes.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Cross-platform sync$q$, $q$Notes sync across Windows, Mac, iOS, Android, and the web, keeping content up to date across all of a user's devices.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Mature, long-established product with reliable sync and deep search across large note archives$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$OCR-based search finds text inside scanned documents, photos, and handwriting, not just typed notes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Newer AI features (AI Assistant, Semantic Search, AI Meeting Notes) are built directly into the note-taking workflow$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Strong Web Clipper for saving full articles and pages with formatting intact$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Broad platform support across Windows, Mac, iOS, Android, and the web$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Free plan is quite restrictive, limited to 50 notes, one notebook, and a single device$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Pricing and plan names have changed multiple times in recent years, creating confusion for existing subscribers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Not built for offline-first or local-only storage, unlike some privacy-focused note-taking alternatives$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Real-time collaborative editing is more limited than dedicated collaboration tools like Notion or Google Docs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$The 2023 acquisition and major layoffs raised ongoing questions among users about long-term product continuity$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Is Evernote free to use?$q$, $q$Yes, Evernote offers a free plan, but it is limited to 50 notes, a single notebook, and one synced device. Anyone taking notes regularly will likely need a paid Starter or Advanced plan for more notes, notebooks, devices, and storage.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$What happened to Evernote's Personal and Professional plans?$q$, $q$Evernote discontinued its previous Personal and Professional subscription tiers and replaced them with Starter and Advanced plans as part of a pricing and plan restructuring.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Does Evernote have AI features?$q$, $q$Yes. Starting with the version 11 release, Evernote added an AI Assistant developed with OpenAI, a Semantic Search mode for natural-language queries, and AI Meeting Notes that transcribe and summarize meetings.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Who owns Evernote now?$q$, $q$Evernote is owned by Bending Spoons, an Italian app company that acquired it in 2023. The acquisition was followed by layoffs of most US and Chile-based staff and a shift of operations to Europe.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$What platforms does Evernote support?$q$, $q$Evernote is available as a web app and has native applications for Windows, Mac, iOS, and Android, with notes syncing across all connected devices.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Personal knowledge base$q$, $q$Individuals use Evernote as a long-term, searchable archive for personal notes, journal entries, ideas, and reference material accumulated over years.$q$, $q$Individuals and knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Meeting notes and recaps$q$, $q$Professionals record and summarize meetings using AI Meeting Notes, capturing discussion points and action items without manual transcription.$q$, $q$Managers and professionals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Web research and clipping$q$, $q$Students and researchers save full articles, pages, and PDFs using the Web Clipper to build an organized, searchable research library.$q$, $q$Students and researchers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Document and receipt archiving$q$, $q$Freelancers and small business owners scan receipts, contracts, and paper documents with the mobile app so the text becomes searchable later.$q$, $q$Freelancers and small business owners$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["50 notes","1 notebook","1 synced device","1 GB monthly uploads","Basic tasks and calendar"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Starter$q$, $q$Approximately $8.25/user/month billed annually (around $99/year), or a higher monthly rate$q$, $q$Monthly or annual$q$, $q$["1,000 notes","20 notebooks","3 synced devices","5 GB monthly uploads","AI Assistant and Semantic Search","Google and Microsoft integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Advanced$q$, $q$Approximately $20.83/user/month billed annually (around $249.99/year), or a higher monthly rate$q$, $q$Monthly or annual$q$, $q$["Unlimited notes, notebooks, and devices","Unlimited monthly uploads","All AI features, including AI Meeting Notes and AI Transcribe","MCP integration for external AI assistants"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, $q$["Single sign-on (SSO)","Centralized administration","User activity logs","Dedicated success manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Evernote is one of the oldest and most recognizable note-taking applications still in active use, originally launched in 2008 by Evernote Corporation, which was founded in 2004. It built its early reputation on a simple promise: capture anything (typed notes, web pages, photos, scanned documents, voice memos) and be able to find it again instantly, even inside images and handwriting, through built-in optical character recognition.$q$, $q$The product changed hands in 2023 when Italian app company Bending Spoons acquired Evernote. The acquisition was followed by significant layoffs of Evernote's US and Chile-based staff and a relocation of operations to Europe, a restructuring that drew considerable attention in the tech press and left some longtime users uncertain about the app's future direction and support. Bending Spoons has since applied a similar playbook to other legacy consumer apps it has acquired, positioning itself as a turnaround owner rather than a typical venture-backed parent.$q$, $q$Since the acquisition, Evernote has resumed active development, culminating in the version 11 release that began rolling out to all users in January 2026. That release introduced native AI features, including an AI Assistant built in collaboration with OpenAI, a semantic (natural-language) search experience, and AI-generated meeting notes, marking Evernote's most substantial product shift in years.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$who-evernote-is-for$q$, $q$Who Evernote Is For$q$, 2, ARRAY[$q$Evernote suits people who accumulate a large, mixed volume of information over time, meeting notes, articles, receipts, scanned documents, photos of whiteboards, and need one searchable place to keep it all. Its OCR-powered search, which can find text inside images and PDFs, is particularly useful for anyone who scans paper documents or clips content from the web regularly.$q$, $q$Knowledge workers, researchers, and consultants who take detailed meeting notes are a natural fit, especially now that AI Meeting Notes can transcribe and summarize both in-person and online meetings directly inside the app. The Web Clipper also makes it a strong choice for anyone doing ongoing research who wants to save full articles, with formatting intact, for later reference.$q$, $q$Long-time users with an existing note archive, and people who value having one app that works consistently across Windows, Mac, iOS, Android, and the web, will also get the most value from Evernote, since much of its appeal comes from continuity and the depth of its search and organization tools built up over many years. It also appeals to people who prefer one general-purpose note tool over juggling a separate app for tasks, a separate one for clipping, and another for scanning documents.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Evernote is not a good fit for people who want to take notes for free without real limits. The free plan restricts users to 50 notes, a single notebook, and one device, which is workable only for very light, occasional use and quickly becomes a bottleneck for anyone taking notes regularly.$q$, $q$Users who prioritize offline-first storage, local-only file control, or strict data-privacy guarantees around AI processing should also think carefully before committing, since Evernote's AI features route note content through third-party model providers and the app is fundamentally cloud-sync-based rather than local-first.$q$, $q$Teams that need deep, real-time collaborative editing, shared databases, or flexible team workspaces are usually better served by tools built around collaboration from the ground up, such as Notion or Google Docs, since Evernote's sharing and collaboration features are comparatively basic. Budget-conscious individuals may also be put off by the pricing changes and plan restructuring Evernote has gone through recently, particularly if they were on legacy plans that no longer exist and now face higher costs to keep the same level of access.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Evernote organizes notes into notebooks, notebook stacks, and tags, with a rich-text editor that supports tables, checklists, and slash commands for quickly inserting content blocks. The Web Clipper browser extension saves full articles, simplified pages, screenshots, or PDFs directly into a notebook, preserving formatting and source links so clipped material stays readable later.$q$, $q$Search is one of Evernote's long-standing differentiators: it indexes text inside scanned documents, photos, and handwritten notes so that a search query can surface content buried inside an image, not just typed text. Built-in document scanning turns a phone camera into a scanner for receipts, whiteboards, and paper documents.$q$, $q$The version 11 release added a set of native AI capabilities: an AI Assistant that can summarize notes, extract action items, and rewrite text, a semantic search mode that understands natural-language queries instead of requiring exact keyword matches, and AI Meeting Notes that record, transcribe, and summarize meetings. Evernote also includes basic task management with due dates and reminders, a template gallery, and integrations with services like Google and Microsoft.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', $q$evernote-experience$q$, $q$The Evernote Experience$q$, 2, ARRAY[$q$Day to day, using Evernote feels like working inside a large, searchable filing cabinet rather than a lightweight scratchpad. The interface is organized around notebooks, tags, and a persistent search bar, and the editor supports enough rich formatting (tables, checklists, attachments) to handle everything from quick to-do lists to lengthy reference documents.$q$, $q$Sync across devices is generally reliable, and the mobile apps make it easy to clip content, snap a photo of a document, or dictate a quick note on the go, with changes appearing on other devices shortly after. The learning curve is modest for basic note-taking but increases somewhat once notebooks, tags, and stacks pile up over years of use, and organizing a large archive well takes some upfront effort.$q$, $q$The newer AI features are woven into the existing note-taking workflow rather than bolted on as a separate tool, so summarizing a note, searching by meaning instead of exact keywords, or reviewing an AI-generated meeting summary all happen inside the same notes users already have. Longtime users may notice the interface and plan structure have shifted noticeably since the Bending Spoons acquisition, reflecting a company actively rebuilding the product after a period of major internal change.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
