INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('332223c1-f22b-409b-9580-2d82c4edda08', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$SmartScan receipt capture$q$, $q$OCR technology reads a photographed or forwarded receipt and automatically fills in the merchant, date, amount, and expense category.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Expensify Card$q$, $q$A corporate charge card with real-time spend controls for admins; card usage can offset the cost of paid subscription plans.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Configurable approval workflows$q$, $q$Multi-level approval chains and spending policies that route expense reports to the right approver before reimbursement.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Mileage tracking$q$, $q$GPS-based mileage logging that calculates reimbursable distance and rate automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Multi-currency support$q$, $q$Expense capture and reimbursement across different currencies for teams with international travel or contractors.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Expensify Travel$q$, $q$Integrated flight, hotel, and car booking with company travel policy compliance built into the booking flow.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Bill Pay$q$, $q$An accounts payable tool that lets finance teams pay vendor invoices directly from the platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Invoicing$q$, $q$Lets freelancers and businesses send client invoices and track when they're paid.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Accounting integrations$q$, $q$Two-way sync with QuickBooks, Xero, NetSuite, Sage Intacct, and other accounting systems.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Real-time reporting dashboard$q$, $q$Gives admins visibility into spend by employee, department, or project as transactions come in.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$SmartScan meaningfully cuts down manual data entry for receipts and expense reports.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$The free plan gives individuals and freelancers a genuinely usable no-cost option for basic tracking.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Combines expense reporting, a corporate card, travel booking, and bill pay instead of requiring several separate vendors.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Broad accounting software integrations ease month-end close for finance teams.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$The mobile apps are polished and make on-the-go expense submission fast and simple.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$The plan structure (individual free tier versus Collect and Control) and card-linked discounts can be confusing to evaluate up front.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Customer support has drawn user complaints about slow response times, especially for account and billing issues.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$SmartScan OCR occasionally misreads handwritten or low-quality receipts, requiring manual correction.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Configuring approval workflows and expense policies has a learning curve for admins setting the system up.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Teams needing deep ERP-style financial controls beyond expenses and travel may find the feature set narrower than a dedicated enterprise finance platform.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Is Expensify free?$q$, $q$Yes. Expensify offers a free plan aimed at individuals tracking their own expenses. Paid Collect and Control plans add team approval workflows, card programs, and deeper accounting integrations for businesses.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$What is SmartScan?$q$, $q$SmartScan is Expensify's OCR-based receipt scanning feature. It automatically reads a photographed or forwarded receipt and fills in the merchant, date, amount, and category so users don't have to enter it manually.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Does Expensify integrate with accounting software?$q$, $q$Yes. Expensify connects with QuickBooks Online and Desktop, Xero, NetSuite, Sage Intacct, and other accounting systems to sync expense data with the general ledger.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$What is the Expensify Card?$q$, $q$The Expensify Card is a corporate charge card issued through Expensify that gives admins real-time spend controls. Its transactions can also offset the cost of paid subscription plans.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Is Expensify a public company?$q$, $q$Yes. Expensify has traded on the Nasdaq under the ticker EXFY since its 2021 IPO.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Freelance and solo expense tracking$q$, $q$Independent workers photograph receipts on the go and let SmartScan categorize them for tax time or client billing, without needing a paid plan.$q$, $q$Freelancers, contractors, and sole proprietors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Small business expense reporting$q$, $q$Employees submit expense reports through the mobile app, managers approve them through a configured workflow, and totals sync automatically to the company's accounting software.$q$, $q$Small business owners and office managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Corporate card and travel spend management$q$, $q$Finance teams issue Expensify Cards with spend limits, book compliant travel through Expensify Travel, and reconcile card transactions in real time against company policy.$q$, $q$Finance and travel teams at mid-size to large companies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Multi-client bookkeeping$q$, $q$Accounting firms and bookkeepers manage expense tracking and reporting across several client accounts from a single login, keeping each client's books current.$q$, $q$Accounting firms and bookkeepers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Track (Free)$q$, $q$Free$q$, $q$N/A$q$, $q$["SmartScan receipt capture for one person","Basic expense categorization","Mileage tracking","A capped number of free SmartScans per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Collect$q$, $q$From approximately $5/user/month with the Expensify Card discount$q$, $q$Monthly or annual$q$, $q$["Expense report submission and basic approval workflow","Expensify Card issuance","Accounting software sync","Standard reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$Control$q$, $q$From approximately $9/user/month with the Expensify Card discount$q$, $q$Monthly or annual$q$, $q$["Advanced multi-level approval workflows","Custom expense policies and domain-level admin controls","Deeper ERP integrations such as NetSuite and Sage Intacct","Expensify Travel and Bill Pay access"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Expensify is expense management software founded in 2008 in San Francisco. The company went public in 2021 and trades on the Nasdaq under the ticker EXFY, making it one of the few standalone expense-management vendors with a public listing. Its core pitch is replacing manual receipt shoeboxes and spreadsheets with a mobile-first workflow that captures, categorizes, and routes spend for reimbursement or accounting.$q$, $q$The signature feature is SmartScan, an OCR engine that reads a photographed or forwarded receipt and automatically fills in the merchant, date, amount, and expense category. From there, expenses can be grouped into reports, routed through an approval chain, and synced to accounting software, cutting down the manual data entry that traditionally makes expense reporting tedious for employees and finance teams alike.$q$, $q$Over time Expensify expanded well beyond receipt capture into a broader spend-management suite: the Expensify Card (a corporate charge card), Expensify Travel (flight and hotel booking), Bill Pay (accounts payable for vendor invoices), and invoicing tools for sending and collecting client payments. The goal is to consolidate several finance workflows — expenses, card spend, travel, and payables — into one connected platform instead of stitching together separate tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$who-expensify-is-for$q$, $q$Who Expensify Is For$q$, 2, ARRAY[$q$Freelancers, contractors, and solo business owners who just need a simple way to log receipts and track deductible spending are a natural fit, since Expensify's free individual plan covers basic scanning and categorization without a subscription.$q$, $q$Small and midsize businesses that need structured expense reports, multi-step approvals, and a two-way sync with accounting platforms like QuickBooks, Xero, or Sage Intacct will get the most value from the paid Collect and Control plans, particularly if they also want to issue a company card with built-in spend controls.$q$, $q$Accounting firms and bookkeepers managing expenses across several client accounts, along with finance and travel teams at larger organizations that want card issuance, travel booking, and bill pay under one vendor relationship, are also well-served by the platform's broader suite.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that need deep, highly customized financial controls beyond expenses and travel — full procurement, complex multi-entity consolidation, or specialized ERP-grade workflows — may find Expensify's feature set narrower than a dedicated enterprise financial platform.$q$, $q$Businesses that are especially sensitive to support responsiveness or pricing clarity should go in with eyes open: Expensify's plan structure and card-linked discounts have historically been described by users as harder to evaluate up front than a flat per-seat price, and customer support wait times have been a recurring complaint.$q$, $q$Very casual users who only want an offline place to keep a handful of receipts without any account setup, subscription friction, or app dependency may find Expensify more platform than they need, since its value grows with report volume, approval complexity, and integrations rather than one-off receipt keeping.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$SmartScan receipt capture reads photographed or emailed receipts to auto-fill merchant, date, amount, and tax details, while GPS-based mileage tracking and multi-currency support handle travel and international spend without manual conversion.$q$, $q$The Expensify Card is a corporate charge card with real-time spend controls for admins, and its usage can offset the cost of paid subscription tiers. Configurable approval workflows and expense policies let admins define spending limits, category rules, and multi-level sign-off chains before a report is reimbursed.$q$, $q$Expensify Travel adds policy-compliant flight, hotel, and car booking inside the same app, Bill Pay lets finance teams pay vendor invoices directly, and built-in invoicing helps users send and track client payments. Two-way integrations with QuickBooks, Xero, NetSuite, and Sage Intacct keep expense data aligned with the general ledger, and a real-time reporting dashboard gives admins visibility into spend by employee, department, or project.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', $q$expensify-experience$q$, $q$The Expensify Experience$q$, 2, ARRAY[$q$Day to day, the experience centers on the mobile app: snap a photo of a receipt, let SmartScan extract the details, tag it to a report, and submit. The camera-first flow is deliberately quick, which is what made Expensify's consumer-grade usability a differentiator against older, form-heavy expense tools.$q$, $q$On the admin side, the web dashboard surfaces pending approvals, policy violations, and card transactions that need reconciling in something closer to real time than a batch monthly close, which helps finance teams catch issues before they pile up at reporting deadlines.$q$, $q$Overall, Expensify delivers on its promise of blending an easy personal expense tool with business-grade controls, though the plan and pricing structure takes some study to map to a specific team's needs, and some users report a learning curve when configuring approval policies or troubleshooting account issues with support.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('22ab0c21-f5e6-4e9a-919f-4e80fdc79abb', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
