INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('77bcbe4d-ff51-41f9-a9da-963c98821e89', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Visual drag-and-drop scheduling$q$, $q$A timeline-based schedule where people are assigned to projects by dragging blocks of time, making team workload easy to see and adjust at a glance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Capacity planning$q$, $q$Availability tracking that surfaces over-booked or under-utilized team members before it affects delivery, factoring in time off automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Time tracking$q$, $q$Team members log actual hours against their scheduled assignments, which feeds into estimates-versus-actuals comparisons.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Project budgeting and rate cards$q$, $q$Estimate project costs by role, apply client and currency rate cards, and track budget burn against the original scope.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Reporting and dashboards$q$, $q$Utilization, budget burn, and margin reporting at both the project and team level, aimed at operations and finance stakeholders.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Time off management$q$, $q$Team members can request and log time off, which is reflected directly in capacity and availability calculations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Placeholder roles for unstaffed work$q$, $q$Provisional, unnamed roles can be scheduled on a project before a specific person is assigned, useful for early-stage project planning.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Integrations and API$q$, $q$Two-way connections with tools like Asana, Jira, Trello, Slack, and calendar apps, plus Zapier and a public API for custom workflows.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Mobile apps$q$, $q$iOS and Android apps for viewing personal schedules, logging time, and managing time-off requests away from a desktop.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Visual, drag-and-drop schedule that's fast to learn and quick to adjust$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Strong capacity planning that surfaces over- or under-booked team members early$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Useful budget, utilization, and margin reporting for operations and finance teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Integrates with common project management tools plus a public API for custom workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$iOS and Android apps let team members check schedules and log time on the go$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Per-seat pricing can add up quickly for larger teams, since most people who appear on the schedule count as a paid seat$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$No permanent free plan, only a 30-day free trial$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Not a full professional services automation suite — no native invoicing or contract billing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Mobile apps are limited to viewing and light updates; adding or editing people and projects requires the desktop version$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Interface is only available in English, with no built-in localization$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$What does Float software actually do?$q$, $q$Float is resource management and team scheduling software. It gives agencies and professional services firms a visual schedule for assigning people to projects, plus capacity planning, time tracking, and reporting on utilization, budgets, and project margins.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$How much does Float cost?$q$, $q$Float uses per-seat pricing with a Starter plan starting at $7 per scheduled person per month and a Pro plan at $12 per scheduled person per month, billed monthly or annually. An Enterprise tier with custom pricing is also available for larger organizations with more advanced needs.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Does Float have a free plan?$q$, $q$No. Float does not offer a permanent free tier. New users get a 30-day free trial (defaulting to the Pro plan features) with no credit card required, after which they choose a paid plan to continue.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$What tools does Float integrate with?$q$, $q$Float connects with project management and communication tools such as Asana, Jira, Trello, Slack, and calendar apps, and supports broader automation through Zapier and a public API for custom integrations.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Is there a Float mobile app?$q$, $q$Yes, Float offers iOS and Android apps for viewing personal schedules, logging time, and submitting time-off requests. Drag-and-drop schedule editing and creating or editing people and projects are only available in the desktop web app.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Staffing a creative or marketing agency across client campaigns$q$, $q$Designers, strategists, and account staff are scheduled against multiple concurrent client campaigns, with capacity planning used to flag when key people are overcommitted before deadlines slip.$q$, $q$Creative and marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Allocating developers and consultants across client engagements$q$, $q$Software and IT consultancies use Float's schedule and budgeting tools to staff developers and consultants against billable client projects while tracking estimates versus actual hours delivered.$q$, $q$Software and IT consultancies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Planning long-horizon project timelines in architecture and engineering$q$, $q$Firms with long project cycles use Float to plan staffing months in advance across several active projects, adjusting assignments as project phases and timelines shift.$q$, $q$Architecture and engineering firms$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Monitoring utilization and project margins across a services business$q$, $q$Operations and finance leaders rely on Float's reporting to track team utilization, budget burn, and profitability across projects, informing staffing and pricing decisions.$q$, $q$Operations directors and finance leaders at professional services firms$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Starter$q$, $q$$7 per scheduled person/month$q$, $q$Monthly or annual (annual billing offers a discount)$q$, $q$["Visual scheduling","Capacity and time-off management","Unlimited project scoping","Project margin tracking","Rate cards","1 placeholder role"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Pro$q$, $q$$12 per scheduled person/month$q$, $q$Monthly or annual (annual billing offers a discount)$q$, $q$["Everything in Starter","Project estimates and actuals tracking","Estimates vs. planned vs. actuals reporting","Delivery dashboards","Client and currency rate cards","Multi-currency projects (up to 5)","SSO and domain restrictions","5 placeholder roles"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual contract$q$, $q$["Everything in Pro","Dedicated customer success manager","Setup, rollout, and training support","Priority support with SLAs","Custom contracts and manual payment options","Unlimited multi-currency projects","Custom placeholder roles"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Float is resource management and team scheduling software built for agencies, consultancies, and other professional services firms that need to plan how their people's time is allocated across multiple projects at once. Launched in 2012, it grew out of a real internal problem its founders faced at an advertising agency: keeping a shared spreadsheet in sync as a growing team juggled overlapping client work. That origin still shapes the product today — Float is oriented around a visual, drag-and-drop schedule rather than a general-purpose project management board.$q$, $q$At its core, Float lets teams see who is working on what, when, and for how long, then adjust assignments as priorities shift. On top of scheduling, it layers capacity planning (spotting over- or under-booked people before it becomes a problem), time tracking against planned hours, and reporting that ties utilization and budget burn back to project profitability. It's designed to sit alongside existing project management tools rather than replace them, syncing with platforms like Asana, Jira, and Trello.$q$, $q$Float remains an independently run, bootstrapped company operating as a fully remote team rather than from a single physical headquarters, and it serves customers across professional services, creative, and technology sectors globally. It competes in a crowded resource-management category alongside tools like Resource Guru, Runn, and Mosaic, generally positioning itself as a more visual, easier-to-adopt option than heavier PSA (professional services automation) suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$who-float-is-for$q$, $q$Who Float Is For$q$, 2, ARRAY[$q$Float is aimed squarely at organizations that staff people against many concurrent projects — creative and marketing agencies, software and IT consultancies, architecture and engineering firms, and other studios where the same designers, developers, or consultants rotate across several client engagements in a given week. If your team's biggest planning headache is knowing who has capacity to take on new work, Float is built for exactly that question.$q$, $q$The typical users are resource managers, operations leads, and project or account managers who need a live view of team availability and workload, plus finance and leadership stakeholders who want visibility into utilization rates and project margins without digging through spreadsheets. Float works well for teams that already run day-to-day task management in another tool and want a dedicated scheduling and capacity layer on top.$q$, $q$It tends to suit teams somewhere in the range of roughly a dozen to a few hundred people — large enough that manual scheduling in spreadsheets has broken down, but not so large that a full enterprise PSA platform with deep financial modules is required. Companies that value a clean, visual interface over configurability will generally find Float's approach a good fit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo freelancers and very small teams managing just their own workload are unlikely to get enough value from Float to justify its per-seat pricing; a personal calendar or simple to-do list will usually cover the same ground with less overhead. Float is built for coordinating multiple people's time against multiple projects, not for individual task management.$q$, $q$Organizations that need a single system covering scheduling, detailed financial billing, invoicing, and contract management should look elsewhere or plan to pair Float with a separate finance tool. Float focuses on scheduling, capacity, time tracking, and profitability reporting — it is not a full professional services automation suite and doesn't natively handle invoicing or complex billing workflows.$q$, $q$Teams that need their software available in languages other than English should also be cautious, since Float's interface currently only ships in English. Similarly, organizations wanting to consolidate task management, scheduling, and time tracking into one single tool (rather than running Float alongside an existing project management platform) may find the need to keep two systems in sync adds friction rather than removing it.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Float is its visual schedule: a drag-and-drop timeline where people are assigned to projects for specific date ranges, making it easy to see workload distribution across a team at a glance and quickly reassign work when priorities change. Capacity planning tools sit on top of this, flagging when someone is booked past their available hours or sitting idle, and tracking time off so it's factored into availability automatically.$q$, $q$On the project side, Float supports budgeting and scoping, letting teams estimate hours and costs by role, apply rate cards, and compare planned effort against actuals as work progresses. Reporting and dashboards translate this into utilization percentages, budget burn, and margin figures for both individual projects and the business as a whole, which is where a lot of the tool's value lands for operations and finance stakeholders.$q$, $q$Time tracking lets team members log actual hours against their scheduled assignments, feeding directly back into the estimates-versus-actuals reporting. Float also connects to commonly used project management and communication tools — Asana, Jira, Trello, Slack, and calendar apps — plus Zapier and a public API for custom integrations, and offers iOS and Android apps so people can check their schedule or log time away from a desktop.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('93f04fea-8e89-4442-8f71-31d6ca1b31e0', $q$float-experience$q$, $q$The Float Experience$q$, 2, ARRAY[$q$New users typically get up to speed quickly, since Float's schedule view is intentionally visual and doesn't require much configuration before it's useful — add people, add projects, and start dragging assignments onto the timeline. That low setup friction is one of the more consistently cited strengths of the product compared to heavier enterprise resourcing tools.$q$, $q$Day to day, the experience centers on frequent small adjustments: moving assignments as scope or priorities shift, logging time against planned work, and checking in on utilization or budget dashboards during status meetings. The mobile apps cover the lighter end of this — viewing a personal schedule, requesting time off, logging hours — but drag-and-drop rescheduling and adding or editing people and projects are desktop-only, so heavier planning work still happens in the browser.$q$, $q$Feedback on Float tends to praise its clarity and ease of use as a scheduling tool, while more critical feedback usually centers on the cost of per-seat pricing as teams scale and on wanting deeper reporting customization or tighter two-way sync with certain project management platforms. Overall, it reads as a focused, well-executed tool for the specific problem of visualizing and planning people's time, rather than an attempt to be an all-in-one operations platform.$q$]::text[], 4);
